import FavoriteBorderRoundedIcon from '@mui/icons-material/FavoriteBorderRounded';
import FavoriteRoundedIcon from '@mui/icons-material/FavoriteRounded';
import { Box, Button, Card, CardActions, CardContent, CardMedia, Grid, Typography, IconButton } from '@mui/material';
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const GoodsItem = (props) => {
    const { id, name, firstPrice, currentPrice, photos, setWishList, wishList } = props;
    const navigate = useNavigate();
    const [isHovered, setIsHovered] = useState(false);
    
    const isInWishList = wishList.some(item => item.id === id);

    return (
        <Grid item xs={12} sm={6} md={6} lg={4}>
            <Card
                onMouseEnter={() => setIsHovered(true)}
                onMouseLeave={() => setIsHovered(false)}
                sx={{
                    position: 'relative',
                    height: '100%',
                    display: 'flex',
                    flexDirection: 'column',
                    borderRadius: '24px',
                    overflow: 'hidden',
                    background: '#171A20',
                    border: '1px solid rgba(255,255,255,0.06)',
                    transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                    '&:hover': {
                        transform: 'translateY(-8px)',
                        borderColor: 'rgba(212, 175, 55, 0.3)',
                        boxShadow: '0 20px 40px rgba(0,0,0,0.4)',
                    },
                }}>
                
                <Box sx={{ position: 'relative', pt: '125%', overflow: 'hidden' }}>
                    <CardMedia
                        component="img"
                        image={photos[0]}
                        alt={name}
                        onClick={() => { navigate("/" + id); window.scrollTo(0, 0) }}
                        sx={{ 
                            position: 'absolute',
                            top: 0,
                            left: 0,
                            width: '100%',
                            height: '100%',
                            objectFit: 'cover',
                            cursor: 'pointer',
                            transition: 'transform 0.6s cubic-bezier(0.4, 0, 0.2, 1)',
                            transform: isHovered ? 'scale(1.05)' : 'scale(1)',
                        }} 
                    />
                    
                    <IconButton
                        onClick={(e) => {
                            e.stopPropagation();
                            setWishList({
                                poster: photos[0],
                                id: id,
                                name: name,
                                price: currentPrice,
                            });
                        }}
                        sx={{
                            position: 'absolute',
                            top: 16,
                            right: 16,
                            backgroundColor: 'rgba(15, 17, 21, 0.6)',
                            backdropFilter: 'blur(8px)',
                            color: isInWishList ? 'primary.main' : 'white',
                            '&:hover': {
                                backgroundColor: 'rgba(15, 17, 21, 0.8)',
                                transform: 'scale(1.1)',
                            },
                        }}
                    >
                        {isInWishList ? <FavoriteRoundedIcon /> : <FavoriteBorderRoundedIcon />}
                    </IconButton>

                    {firstPrice && (
                        <Box
                            sx={{
                                position: 'absolute',
                                top: 16,
                                left: 16,
                                backgroundColor: 'primary.main',
                                color: 'background.default',
                                px: 1.5,
                                py: 0.5,
                                borderRadius: '8px',
                                fontWeight: 700,
                                fontSize: '0.75rem',
                                textTransform: 'uppercase',
                                letterSpacing: '0.05em',
                            }}
                        >
                            Sale
                        </Box>
                    )}
                </Box>

                <CardContent sx={{ flexGrow: 1, p: 3, pb: 1 }}>
                    <Typography
                        variant="body2"
                        sx={{ 
                            color: 'text.secondary', 
                            textTransform: 'uppercase', 
                            letterSpacing: '0.1em', 
                            fontSize: '0.7rem',
                            mb: 1,
                            fontWeight: 600
                        }}
                    >
                        Premium Collection
                    </Typography>
                    <Typography
                        variant="h6"
                        onClick={() => { navigate("/" + id); window.scrollTo(0, 0) }}
                        sx={{ 
                            fontWeight: 700, 
                            cursor: 'pointer',
                            mb: 1.5,
                            fontSize: '1.1rem',
                            lineHeight: 1.2,
                            '&:hover': { color: 'primary.main' }
                        }}
                    >
                        {name}
                    </Typography>
                    
                    <Box sx={{ display: 'flex', alignItems: 'baseline', gap: 1.5 }}>
                        <Typography variant="h6" sx={{ fontWeight: 800, color: 'primary.main' }}>
                            {currentPrice} ₴
                        </Typography>
                        {firstPrice && (
                            <Typography 
                                variant="body2" 
                                sx={{ 
                                    textDecoration: 'line-through', 
                                    color: 'text.muted',
                                    opacity: 0.6 
                                }}
                            >
                                {firstPrice} ₴
                            </Typography>
                        )}
                    </Box>
                </CardContent>

                <CardActions sx={{ p: 3, pt: 1 }}>
                    <Button 
                        fullWidth
                        variant={isHovered ? "contained" : "outlined"}
                        onClick={() => { navigate("/" + id); window.scrollTo(0, 0) }}
                        sx={{
                            height: '48px',
                            borderRadius: '12px',
                            fontWeight: 700,
                            letterSpacing: '0.02em',
                            transition: 'all 0.3s ease',
                        }}
                    >
                        View Details
                    </Button>
                </CardActions>
            </Card>
        </Grid>
    );
};

export default GoodsItem;
